SELECT b.*, ste.site_nm AS site_nm, bct.blog_cate_nm AS blog_cate_nm, prd.prod_nm AS prod_nm FROM cm_bltn b LEFT JOIN sy_site ste ON ste.site_id = b.site_id LEFT JOIN cm_bltn_cate bct ON bct.blog_cate_id = b.blog_cate_id LEFT JOIN pd_prod prd ON prd.prod_id = b.prod_id
ORDER BY b.blog_id ASC ORDER BY b.blog_id DESC ORDER BY b.blog_title ASC ORDER BY b.blog_title DESC ORDER BY b.reg_date ASC ORDER BY b.reg_date DESC ORDER BY b.reg_date DESC
LIMIT #{p.limit} OFFSET #{p.offset}

